#include <bits/stdc++.h>
using namespace std;

int par[100001];
int rk[100001]; // parity to parent

int find(int x){
    if(par[x]==x) return x;
    int root=find(par[x]);
    rk[x]^=rk[par[x]];
    par[x]=root;
    return root;
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, m; cin >> n >> m;
    for(int i=1;i<=n;i++){ par[i]=i; rk[i]=0; }
    vector<int> bad;
    for(int i=1;i<=m;i++){
        int a,b,s; cin >> a >> b >> s;
        int ra=find(a), rb=find(b);
        if(ra==rb){
            if((rk[a]^rk[b])!=s) bad.push_back(i);
        } else {
            // attach ra under rb with parity: rk[ra] s.t. rk[a]^rk[ra]^rk[b]... 
            // need rk[a] (to ra) , set ra's parity so that a^b == s
            // rk[a] xor newRk[ra] xor rk[b] = s => newRk[ra] = s xor rk[a] xor rk[b]
            par[ra]=rb;
            rk[ra]= s ^ rk[a] ^ rk[b];
        }
    }
    if(bad.empty()) cout << "OK\n";
    else {
        for(size_t i=0;i<bad.size();i++){ if(i) cout << ' '; cout << bad[i]; }
        cout << "\n";
    }
    return 0;
}
